24. What will be the output of the following JavaScript code?
const arr = [10, 20, 30];
let result = 0;
arr.forEach(myFunction);
document.write("Result: ", result);
function myFunction(value, index, array) {
result += value;
}

25. What will be the output of the following JavaScript code?
const values = [10, 20, 30];
const result = values.map(myFunction);
document.write("Result: ", result);
function myFunction(value, index, array) {
return value * value;
}

28. What will be the output of this JavaScript code?
